from minimarkdown import Markdown
from html.parser import HTMLParser

class Headings(HTMLParser):
    def __init__(self):
        super().__init__()
        self.rows = []
        self.current = None
    def handle_starttag(self, tag, attrs):
        if tag in ['h1', 'h2', 'h3', 'h4', 'h5', 'h6']:
            self.current = {'level': int(tag[1]), 'id': dict(attrs).get('id'), 'text': ''}
    def handle_data(self, data):
        if self.current is not None:
            self.current['text'] += data
    def handle_endtag(self, tag):
        if self.current is not None and tag == 'h%s' % self.current['level']:
            self.rows.append(self.current)
            self.current = None

doc = '''# API & **SDK**

## API `SDK`

# API SDK'''
m = Markdown()
tree = m.parse(doc)
toc = m.toc(doc)
html = m.render(tree)
p = Headings(); p.feed(html)
ids = ['api-sdk', 'api-sdk-2', 'api-sdk-3']
print([h.get('attrs', {}).get('id') for h in tree if h.get('type') == 'heading'] == ids)
print([h['id'] for h in p.rows] == [e['id'] for e in toc] == ids)
print([h['text'] for h in p.rows] == [e['text'] for e in toc] == ['API & SDK', 'API SDK', 'API SDK'])

