from minimarkdown import Markdown
from html.parser import HTMLParser

class Inputs(HTMLParser):
    def __init__(self):
        super().__init__(); self.inputs = []
    def handle_starttag(self, tag, attrs):
        if tag == 'input':
            self.inputs.append(dict(attrs))

def count_type(md, tree, kind):
    return sum(1 for n in md.walk(tree) if isinstance(n, dict) and n.get('type') == kind)

doc = '- [x] **Done**\n- [ ] [Todo](https://e.test)'
m = Markdown(plugins=['task_list'])
tree = m.parse(doc)
html = m.render(tree)
p = Inputs(); p.feed(html)
items = tree[0].get('items', []) if tree else []
print([item.get('checked') for item in items] == [True, False])
print(count_type(m, tree, 'strong') == 1, count_type(m, tree, 'link') == 1)
print(len(p.inputs) == 2 and 'checked' in p.inputs[0] and 'checked' not in p.inputs[1])

from minimarkdown import Markdown
from html.parser import HTMLParser

class Seen(HTMLParser):
    def __init__(self):
        super().__init__(); self.tags = []; self.data = []
    def handle_starttag(self, tag, attrs):
        self.tags.append(tag)
    def handle_data(self, data):
        self.data.append(data)

def count_type(md, tree, kind):
    return sum(1 for n in md.walk(tree) if isinstance(n, dict) and n.get('type') == kind)

doc = 'Inline `**<x>**` here.\n\n```html\n<strong>& raw</strong>\n```'
m = Markdown()
tree = m.parse(doc)
html = m.render(tree)
p = Seen(); p.feed(html)
all_data = '\n'.join(p.data)
print('strong' not in p.tags, '**<x>**' in all_data, '<strong>& raw</strong>' in all_data)
print(count_type(m, tree, 'strong') == 0, count_type(m, tree, 'code_span') == 1, count_type(m, tree, 'block_code') == 1)
